+type AsyncTick = () => Promise<void> | void;
+
+export type TypingKeepaliveLoop = {
+  tick: () => Promise<void>;
+  start: () => void;
+  stop: () => void;
+  isRunning: () => boolean;
+};
+
+export function createTypingKeepaliveLoop(params: {
+  intervalMs: number;
+  onTick: AsyncTick;
+}): TypingKeepaliveLoop {
+  let timer: ReturnType<typeof setInterval> | undefined;
+  let tickInFlight = false;
+
+  const tick = async () => {
+    if (tickInFlight) {
+      return;
+    }
+    tickInFlight = true;
+    try {
+      await params.onTick();
+    } finally {
+      tickInFlight = false;
+    }
+  };
